// Utilitário de tradução automática gratuita usando Google Translate web API
class AutoTranslator {
  private cache: Map<string, Map<string, string>> = new Map();
  private currentLanguage: string = 'pt';
  private originalTexts: Map<Text, string> = new Map(); // Referência direta aos nós
  private isInitialized: boolean = false;

  constructor() {
    this.currentLanguage = localStorage.getItem('language') || 'pt';

    // Armazenar textos originais quando a página carrega
    if (typeof window !== 'undefined') {
      // Usar MutationObserver para detectar quando o DOM está pronto
      const observer = new MutationObserver(() => {
        if (!this.isInitialized && document.body) {
          setTimeout(() => {
            this.initializeOriginalTexts();
          }, 100);
        }
      });

      observer.observe(document, { 
        childList: true, 
        subtree: true,
        attributes: false 
      });

      // Fallback se MutationObserver não disparar
      setTimeout(() => {
        if (!this.isInitialized) {
          this.initializeOriginalTexts();
        }
      }, 1000);
    }
  }

  setLanguage(lang: string) {
    if (this.currentLanguage === lang) return; // Evitar operações duplicadas

    console.log(`Definindo idioma para: ${lang}`);

    // Se mudando para português, garantir que temos textos originais
    if (lang === 'pt' && this.currentLanguage !== 'pt') {
      console.log('Mudando para português, verificando textos originais...');
      // Se não temos textos originais, armazenar antes de mudar
      if (this.originalTexts.size === 0) {
        console.log('Nenhum texto original armazenado, armazenando textos atuais...');
        // Armazenar textos atuais como se fossem originais (fallback)
        this.storeOriginalTexts();
      }
    }

    this.currentLanguage = lang;
    localStorage.setItem('language', lang);

    // Garantir que textos originais estão armazenados
    if (!this.isInitialized) {
      this.initializeOriginalTexts();
    }

    // Se voltar para português, restaurar texto original
    if (lang === 'pt') {
      console.log('Restaurando texto português original...');
      this.restoreOriginalTexts();
    } else {
      console.log(`Traduzindo para ${lang}...`);
      this.translatePage();
    }
  }

  getCurrentLanguage(): string {
    return this.currentLanguage;
  }

  // Inicializar textos originais (unificado)
  private initializeOriginalTexts() {
    if (!document.body) return;

    console.log('Inicializando textos originais...');
    this.storeOriginalTexts(document.body);
    this.isInitialized = true;
  }

  // Traduzir texto usando Google Translate web API (grátis)
  async translateText(text: string, fromLang: string = 'pt', toLang: string = 'en'): Promise<string> {
    if (fromLang === toLang) return text;

    // Verificar cache primeiro
    const cacheKey = `${fromLang}-${toLang}`;
    if (!this.cache.has(cacheKey)) {
      this.cache.set(cacheKey, new Map());
    }
    const langCache = this.cache.get(cacheKey)!;

    if (langCache.has(text)) {
      return langCache.get(text)!;
    }

    try {
      // Usar Google Translate web API (grátis)
      const url = `https://translate.googleapis.com/translate_a/single?client=gtx&sl=${fromLang}&tl=${toLang}&dt=t&q=${encodeURIComponent(text)}`;

      const response = await fetch(url);
      if (!response.ok) {
        throw new Error('API de tradução falhou');
      }

      const data = await response.json();
      if (data && data[0] && data[0][0] && data[0][0][0]) {
        const translatedText = data[0][0][0];
        langCache.set(text, translatedText);
        return translatedText;
      }
    } catch (error) {
      console.warn('Tradução falhou, usando texto original:', error);
    }

    return text; // Fallback para texto original
  }

  // Traduzir todos os nós de texto da página
  async translatePage() {
    if (this.currentLanguage === 'pt') return; // Pular se for português (original)

    const textNodes = this.getTextNodes(document.body);
    const translations: Promise<void>[] = [];

    for (const node of textNodes) {
      const originalText = node.textContent?.trim();
      if (originalText && originalText.length > 0) {
        translations.push(
          this.translateText(originalText, 'pt', this.currentLanguage)
            .then(translated => {
              if (node.textContent) {
                node.textContent = translated;
              }
            })
        );
      }
    }

    await Promise.all(translations);
  }

  // Get all text nodes from an element
  private getTextNodes(element: Element): Text[] {
    const textNodes: Text[] = [];
    const walker = document.createTreeWalker(
      element,
      NodeFilter.SHOW_TEXT,
      {
        acceptNode: (node) => {
          // Skip script, style, and input elements
          const parent = node.parentElement;
          if (!parent) return NodeFilter.FILTER_REJECT;

          const tagName = parent.tagName.toLowerCase();
          if (['script', 'style', 'noscript', 'input', 'textarea'].includes(tagName)) {
            return NodeFilter.FILTER_REJECT;
          }

          // Skip if text is just whitespace
          if (!node.textContent?.trim()) {
            return NodeFilter.FILTER_REJECT;
          }

          // Skip protected elements
          if (this.isProtectedElement(parent)) {
            return NodeFilter.FILTER_REJECT;
          }

          // Skip if text contains only emojis or flags
          if (this.isEmojiOrFlagOnly(node.textContent)) {
            return NodeFilter.FILTER_REJECT;
          }

          return NodeFilter.FILTER_ACCEPT;
        }
      }
    );

    let node;
    // eslint-disable-next-line no-cond-assign
    while (node = walker.nextNode()) {
      textNodes.push(node as Text);
    }

    return textNodes;
  }

  // Check if element should be protected from translation
  private isProtectedElement(element: Element): boolean {
    // Check for data-no-translate attribute
    if (element.hasAttribute('data-no-translate') && element.getAttribute('data-no-translate') === 'true') {
      return true;
    }

    // Check for no-translate class
    if (element.classList.contains('no-translate')) {
      return true;
    }

    // Check for role="img" (icons, flags, etc.)
    if (element.getAttribute('role') === 'img') {
      return true;
    }

    // Check if element or any parent is an SVG
    if (element.closest('svg')) {
      return true;
    }

    // Check if element is an image
    if (element.tagName.toLowerCase() === 'img') {
      return true;
    }

    // Check if element contains only emoji/flag patterns
    const text = element.textContent?.trim();
    if (text && this.isEmojiOrFlagOnly(text)) {
      return true;
    }

    return false;
  }

  // Check if text contains only emojis or flags
  private isEmojiOrFlagOnly(text: string): boolean {
    // Remove whitespace
    const trimmed = text.trim();
    if (!trimmed) return false;

    // Check if text contains only flag emojis (🇺🇸, 🇧🇷, 🇪🇸, etc.)
    const flagRegex = /^[\p{RI}\p{Emoji}]+$/u;

    // Check if it's mainly emojis (more than 50% emoji characters)
    const emojiRegex = /[\p{Emoji}\p{RI}]/gu;
    const emojiMatches = trimmed.match(emojiRegex) || [];
    const emojiRatio = emojiMatches.length / trimmed.length;

    return flagRegex.test(trimmed) || emojiRatio > 0.5;
  }

  // Translate a specific element
  async translateElement(element: Element) {
    if (this.currentLanguage === 'pt') return;

    const textNodes = this.getTextNodes(element);
    const translations: Promise<void>[] = [];

    for (const node of textNodes) {
      const originalText = node.textContent?.trim();
      if (originalText && originalText.length > 0) {
        translations.push(
          this.translateText(originalText, 'pt', this.currentLanguage)
            .then(translated => {
              if (node.textContent) {
                node.textContent = translated;
              }
            })
        );
      }
    }

    await Promise.all(translations);
  }

  // Store original texts for all elements (unificado)
  storeOriginalTexts(element: Element = document.body) {
    const textNodes = this.getTextNodes(element);
    console.log(`Encontrados ${textNodes.length} nós de texto para armazenar`);

    let storedCount = 0;
    for (const node of textNodes) {
      if (node.textContent) {
        const text = node.textContent.trim();
        if (text.length > 0) {
          // Armazenar APENAS se o idioma atual for português
          // e se ainda não tiver sido armazenado
          if (this.currentLanguage === 'pt' && !this.originalTexts.has(node)) {
            this.originalTexts.set(node, text);
            storedCount++;
            console.log(`Armazenando original: "${text}"`);
          }
        }
      }
    }

    console.log(`Armazenados ${storedCount} textos originais`);
    console.log(`Total de textos armazenados: ${this.originalTexts.size}`);
  }

  // Restaurar textos originais (usando referência direta)
  restoreOriginalTexts(element: Element = document.body) {
    console.log('Iniciando restauração de textos originais...');

    let restoredCount = 0;

    // Restaurar usando referência direta aos nós
    for (const [node, originalText] of this.originalTexts) {
      if (node.isConnected && node.textContent !== originalText) {
        if (restoredCount < 3) {
          console.log(`Restaurando: "${node.textContent}" -> "${originalText}"`);
        }
        node.textContent = originalText;
        restoredCount++;
      }
    }

    console.log(`Restaurados ${restoredCount} textos para português original`);

    // Se nenhum texto foi restaurado, limpar e re-inicializar apenas se estiver em português
    if (restoredCount === 0 && this.isInitialized && this.currentLanguage === 'pt') {
      console.log('Nenhum texto restaurado e estamos em português, re-inicializando...');
      this.originalTexts.clear();
      this.isInitialized = false;
      this.initializeOriginalTexts();
    }
  }
}

// Create global instance
export const autoTranslator = new AutoTranslator();

// Hook for React components
export const useAutoTranslate = () => {
  return {
    translate: (text: string, toLang?: string) => 
      autoTranslator.translateText(text, 'pt', toLang || autoTranslator.getCurrentLanguage()),
    setLanguage: (lang: string) => autoTranslator.setLanguage(lang),
    getCurrentLanguage: () => autoTranslator.getCurrentLanguage(),
    translatePage: () => autoTranslator.translatePage(),
    translateElement: (element: Element) => autoTranslator.translateElement(element)
  };
};
